namespace sv_5f24129186a9429ea42555359f539e5b.Models;

// Immutable records for submission
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
}

using sv_5f24129186a9429ea42555359f539e5b.Models;

namespace sv_5f24129186a9429ea42555359f539e5b.Services;

public class ApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        await Task.Delay(1000); // Simulate network call
        return Interlocked.Increment(ref _nextId);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        await Task.Delay(300); // Simulate validation
        return !string.IsNullOrWhiteSpace(email)
            && email.Contains('@')
            && email.Contains('.');
    }
}

@namespace sv_5f24129186a9429ea42555359f539e5b.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application progress">
    <ol>
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepNumber = i + 1;
            var status = GetStepStatus(stepNumber);
            <li class="step @status">
                @if (status == "completed")
                {
                    <button type="button" class="step-btn" @onclick="() => OnStepClicked.InvokeAsync(stepNumber)">
                        <span class="step-circle">&#10003;</span>
                        <span class="step-label">@StepNames[i]</span>
                    </button>
                }
                else
                {
                    <span class="step-btn" aria-current="@(status == "active" ? "step" : null)">
                        <span class="step-circle">@stepNumber</span>
                        <span class="step-label">@StepNames[i]</span>
                    </span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];

    private string GetStepStatus(int step)
    {
        if (step == CurrentStep) return "active";
        if (CompletedSteps.Contains(step)) return "completed";
        return "future";
    }
}

nav.step-indicator ol {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0 0 2rem;
    counter-reset: step;
}

.step {
    flex: 1;
    text-align: center;
    position: relative;
}

.step + .step::before {
    content: "";
    position: absolute;
    top: 18px;
    left: -50%;
    width: 100%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step.completed + .step::before,
.step.active + .step::before {
    background: transparent;
    background-image: linear-gradient(to right, #198754, #dee2e6);
}

.step.completed + .step.completed::before,
.step.completed + .step.active::before {
    background: #198754;
    background-image: none;
}

.step-btn {
    display: inline-flex;
    flex-direction: column;
    align-items: center;
    gap: 0.4rem;
    background: none;
    border: none;
    cursor: default;
    padding: 0;
    position: relative;
    z-index: 1;
}

button.step-btn {
    cursor: pointer;
}

button.step-btn:hover .step-circle {
    box-shadow: 0 0 0 3px rgba(25, 135, 84, 0.25);
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.85rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

.step.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-label {
    font-size: 0.78rem;
    color: #6c757d;
    white-space: nowrap;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

@namespace sv_5f24129186a9429ea42555359f539e5b.Components.Pages.Apply
@using sv_5f24129186a9429ea42555359f539e5b.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input class="form-control" @bind="Entry.Company" @bind:event="oninput" placeholder="Company name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input class="form-control" @bind="Entry.Title" @bind:event="oninput" placeholder="Job title" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" @bind="Entry.StartDate" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index" @bind="Entry.IsCurrent"
                           @onclick="HandleCurrentToggle" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" @bind="Entry.Description" @bind:event="oninput"
                          placeholder="Describe your responsibilities and achievements"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private void HandleCurrentToggle()
    {
        if (!Entry.IsCurrent)
        {
            Entry.EndDate = null;
        }
    }
}

