nav.step-indicator ol {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0 0 2rem;
    counter-reset: step;
}

.step {
    flex: 1;
    text-align: center;
    position: relative;
}

.step + .step::before {
    content: "";
    position: absolute;
    top: 18px;
    left: -50%;
    width: 100%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step.completed + .step::before,
.step.active + .step::before {
    background: transparent;
    background-image: linear-gradient(to right, #198754, #dee2e6);
}

.step.completed + .step.completed::before,
.step.completed + .step.active::before {
    background: #198754;
    background-image: none;
}

.step-btn {
    display: inline-flex;
    flex-direction: column;
    align-items: center;
    gap: 0.4rem;
    background: none;
    border: none;
    cursor: default;
    padding: 0;
    position: relative;
    z-index: 1;
}

button.step-btn {
    cursor: pointer;
}

button.step-btn:hover .step-circle {
    box-shadow: 0 0 0 3px rgba(25, 135, 84, 0.25);
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.85rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

.step.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-label {
    font-size: 0.78rem;
    color: #6c757d;
    white-space: nowrap;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

