@namespace sv_5f24129186a9429ea42555359f539e5b.Components.Pages.Apply
@using sv_5f24129186a9429ea42555359f539e5b.Models

<h4 class="mb-4">Personal Information</h4>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

<div class="row g-3 mb-4">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State" />
    </div>
</div>

<div class="d-flex justify-content-end">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next →</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private List<string> Errors { get; set; } = new();
    private bool IsValidating { get; set; }

    private async Task HandleNext()
    {
        Errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.FullName)) Errors.Add("Full name is required.");
        if (string.IsNullOrWhiteSpace(Model.Email)) Errors.Add("Email is required.");
        if (string.IsNullOrWhiteSpace(Model.Phone)) Errors.Add("Phone is required.");
        if (string.IsNullOrWhiteSpace(Model.Address)) Errors.Add("Address is required.");

        if (Errors.Count > 0) return;

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                Errors.Add("Please enter a valid email address.");
                return;
            }
            await OnNext.InvokeAsync();
        }
        finally
        {
            IsValidating = false;
        }
    }
}

@namespace sv_5f24129186a9429ea42555359f539e5b.Components.Pages.Apply
@using sv_5f24129186a9429ea42555359f539e5b.Models

<h4 class="mb-4">Work History</h4>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryEditor Entry="Entries[index]"
                     Index="index"
                     CanRemove="Entries.Count > 1"
                     OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-4" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> Errors { get; set; } = new();

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            var e = Entries[i];
            var pos = i + 1;
            if (string.IsNullOrWhiteSpace(e.Company)) Errors.Add($"Position {pos}: Company name is required.");
            if (string.IsNullOrWhiteSpace(e.Title)) Errors.Add($"Position {pos}: Job title is required.");
            if (e.StartDate is null) Errors.Add($"Position {pos}: Start date is required.");
        }

        if (Errors.Count == 0)
            await OnNext.InvokeAsync();
    }
}

@namespace sv_5f24129186a9429ea42555359f539e5b.Components.Pages.Apply
@using sv_5f24129186a9429ea42555359f539e5b.Models

<h4 class="mb-4">References</h4>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceEditor Reference="References[index]"
                     Index="index"
                     CanRemove="References.Count > 2"
                     OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-4" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> Errors { get; set; } = new();

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            var num = i + 1;
            if (string.IsNullOrWhiteSpace(r.Name)) Errors.Add($"Reference {num}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship)) Errors.Add($"Reference {num}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email)) Errors.Add($"Reference {num}: Email is required.");
            if (string.IsNullOrWhiteSpace(r.Phone)) Errors.Add($"Reference {num}: Phone is required.");
        }

        if (Errors.Count == 0)
            await OnNext.InvokeAsync();
    }
}

@namespace sv_5f24129186a9429ea42555359f539e5b.Components.Pages.Apply

<h4 class="mb-4">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="12" @bind="CoverLetter" @bind:event="oninput"
              maxlength="@MaxLength"
              placeholder="Tell us why you're a great fit for this role…"></textarea>
    <div class="form-text text-end">
        @CoverLetter.Length / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;

    private async Task HandleNext()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
        await OnNext.InvokeAsync();
    }
}

@namespace sv_5f24129186a9429ea42555359f539e5b.Components.Pages.Apply
@using sv_5f24129186a9429ea42555359f539e5b.Models

<h4 class="mb-4">Review Your Application</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@if (SubmittedId.HasValue)
{
    <div class="alert alert-success text-center">
        <h5>🎉 Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-child-no-border">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted small">
