@namespace sv_5f24129186a9429ea42555359f539e5b.Components.Pages.Apply
@using sv_5f24129186a9429ea42555359f539e5b.Models

<h4 class="mb-4">Personal Information</h4>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

<div class="row g-3 mb-4">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State" />
    </div>
</div>

<div class="d-flex justify-content-end">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next →</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private List<string> Errors { get; set; } = new();
    private bool IsValidating { get; set; }

    private async Task HandleNext()
    {
        Errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.FullName)) Errors.Add("Full name is required.");
        if (string.IsNullOrWhiteSpace(Model.Email)) Errors.Add("Email is required.");
        if (string.IsNullOrWhiteSpace(Model.Phone)) Errors.Add("Phone is required.");
        if (string.IsNullOrWhiteSpace(Model.Address)) Errors.Add("Address is required.");

        if (Errors.Count > 0) return;

        IsValidating = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                Errors.Add("Please enter a valid email address.");
                return;
            }
            await OnNext.InvokeAsync();
        }
        finally
        {
            IsValidating = false;
        }
    }
}

