@namespace sv_5f24129186a9429ea42555359f539e5b.Components.Pages.Apply
@using sv_5f24129186a9429ea42555359f539e5b.Models

<h4 class="mb-4">Work History</h4>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">
        <ul class="mb-0">
            @foreach (var error in Errors)
            {
                <li>@error</li>
            }
        </ul>
    </div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryEditor Entry="Entries[index]"
                     Index="index"
                     CanRemove="Entries.Count > 1"
                     OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-4" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> Errors { get; set; } = new();

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            var e = Entries[i];
            var pos = i + 1;
            if (string.IsNullOrWhiteSpace(e.Company)) Errors.Add($"Position {pos}: Company name is required.");
            if (string.IsNullOrWhiteSpace(e.Title)) Errors.Add($"Position {pos}: Job title is required.");
            if (e.StartDate is null) Errors.Add($"Position {pos}: Start date is required.");
        }

        if (Errors.Count == 0)
            await OnNext.InvokeAsync();
    }
}

