    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            var num = i + 1;
            if (string.IsNullOrWhiteSpace(r.Name)) Errors.Add($"Reference {num}: Name is required.");
            if (string.IsNullOrWhiteSpace(r.Relationship)) Errors.Add($"Reference {num}: Relationship is required.");
            if (string.IsNullOrWhiteSpace(r.Email)) Errors.Add($"Reference {num}: Email is required.");
            if (string.IsNullOrWhiteSpace(r.Phone)) Errors.Add($"Reference {num}: Phone is required.");
        }

        if (Errors.Count == 0)
            await OnNext.InvokeAsync();
    }
}

