@page "/apply"
@using sv_5f24129186a9429ea42555359f539e5b.Models
@using sv_5f24129186a9429ea42555359f539e5b.Components.Pages.Apply
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 1:
            <PersonalInfoStep Model="_personal"
                              ApplicationService="ApplicationService"
                              OnNext="() => AdvanceToStep(2)" />
            break;
        case 2:
            <WorkHistoryStep Entries="_workEntries"
                             OnBack="() => GoToStep(1)"
                             OnNext="() => AdvanceToStep(3)" />
            break;
        case 3:
            <ReferencesStep References="_references"
                            OnBack="() => GoToStep(2)"
                            OnNext="() => AdvanceToStep(4)" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="_coverLetter"
                             OnBack="() => GoToStep(3)"
                             OnNext="() => AdvanceToStep(5)" />
            break;
        case 5:
            <ReviewStep Personal="_personal"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="@_coverLetter"
                        OnBack="() => GoToStep(4)"
                        OnEditStep="GoToStep"
                        OnSubmit="SubmitApplication"
                        IsSubmitting="_isSubmitting"
                        SubmittedId="_submittedId"
                        ErrorMessage="@_errorMessage" />
            break;
    }
</div>

@code {
    private int _currentStep = 1;
    private readonly HashSet<int> _completedSteps = new();

    // Form state
    private readonly PersonalInfoModel _personal = new();
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };
    private string _coverLetter = "";

    // Submission state
    private bool _isSubmitting;
    private int? _submittedId;
    private string? _errorMessage;

    private void GoToStep(int step)
    {
        if (step == _currentStep) return;
        if (_completedSteps.Contains(step) || step < _currentStep)
        {
            _currentStep = step;
        }
    }

    private void AdvanceToStep(int nextStep)
    {
        _completedSteps.Add(_currentStep);
        _currentStep = nextStep;
    }

    private async Task SubmitApplication()
    {
        _isSubmitting = true;
        _errorMessage = null;

        try
        {
            var application = new JobApplication(
                new PersonalInfo(_personal.FullName, _personal.Email, _personal.Phone, _personal.Address),
                new WorkHistory(_workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate!.Value,
                    e.IsCurrent ? null : e.EndDate,
                    e.Description)).ToList()),
                _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                _coverLetter
            );

            _submittedId = await ApplicationService.SubmitApplicationAsync(application);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            _isSubmitting = false;
        }
    }
}

